public class Car {
    String make;
    String model;
    int year;
    double price;

    // Constructor 1: fully parameterised
    public Car(String make, String model, int year, double price) {
        this.make  = make;
        this.model = model;
        this.year  = year;
        this.price = price;
    }

    // Constructor 2: no price (defaults to 0.0)
    public Car(String make, String model, int year) {
        this.make  = make;
        this.model = model;
        this.year  = year;
        this.price = 0.0;  // default
    }

    // Constructor 3: only make and model (year defaults to current year)
    public Car(String make, String model) {
        this.make  = make;
        this.model = model;
        this.year  = 2024;
        this.price = 0.0;
    }

    public String toString() {
        return year + " " + make + " " + model + " $" + price;
    }

    public static void main(String[] args) {
        Car c1 = new Car("Toyota", "Corolla", 2022, 25000.0);
        Car c2 = new Car("Honda",  "Civic",   2021);
        Car c3 = new Car("Ford",   "Focus");

        System.out.println(c1); // 2022 Toyota Corolla $25000.0
        System.out.println(c2); // 2021 Honda Civic $0.0
        System.out.println(c3); // 2024 Ford Focus $0.0
    }
}

public class Car {
    String make;
    String model;
    int year;
    double price;

    // Master constructor: does all the real work
    public Car(String make, String model, int year, double price) {
        this.make  = make;
        this.model = model;
        this.year  = year;
        this.price = price;
        System.out.println("Master constructor called");
    }

    // Delegates to master, supplying default price
    public Car(String make, String model, int year) {
        this(make, model, year, 0.0); // MUST be first statement
        System.out.println("3-param constructor called");
    }

    // Delegates to 3-param constructor
    public Car(String make, String model) {
        this(make, model, 2024); // MUST be first statement
        System.out.println("2-param constructor called");
    }

    public static void main(String[] args) {
        System.out.println("--- Creating c1 ---");
        Car c1 = new Car("Ford", "Focus");
        // Output order:
        //   Master constructor called
        //   3-param constructor called
        //   2-param constructor called
        // The chain runs deepest-first, prints on the way back up!
    }
}

public class Robot {
    // Static field: ONE copy shared by ALL Robot objects
    static int instanceCount = 0;

    // Instance fields: each Robot has its own copy
    String name;
    int id;

    public Robot(String name) {
        instanceCount++;          // increments the shared counter
        this.id   = instanceCount; // records THIS robot's ID
        this.name = name;
    }

    public static void main(String[] args) {
        System.out.println(Robot.instanceCount); // 0 — no objects yet

        Robot r1 = new Robot("Alpha");
        System.out.println(Robot.instanceCount); // 1
        System.out.println(r1.id);               // 1

        Robot r2 = new Robot("Beta");
        Robot r3 = new Robot("Gamma");
        System.out.println(Robot.instanceCount); // 3
        System.out.println(r2.id + " " + r3.id); // 2 3

        // All three references to instanceCount are identical:
        System.out.println(r1.instanceCount); // 3 (same shared field!)
        System.out.println(r2.instanceCount); // 3
        System.out.println(Robot.instanceCount); // 3
    }
}

public class MathUtils {
    // Static constant
    static final double PI = 3.14159265358979;

    // Static field
    static int callCount = 0;

    // Instance field
    double value;

    public MathUtils(double v) { this.value = v; }

    // Static method: no 'this'; can only use static members directly
    public static double circleArea(double radius) {
        callCount++;          // OK: static field
        return PI * radius * radius; // OK: static field
        // return value * 2; // COMPILE ERROR: 'value' is an instance field
    }

    // Instance method: has 'this'; can use both instance AND static members
    public double doubled() {
        callCount++;          // OK: static field accessible from instance method
        return this.value * 2; // OK: instance field
    }

    // Static factory method: creates and returns an object
    public static MathUtils fromString(String s) {
        double d = Double.parseDouble(s);
        return new MathUtils(d); // static method CAN create objects
    }

    public static void main(String[] args) {
        // Calling static methods: use ClassName (preferred)
        double area = MathUtils.circleArea(5.0);
        System.out.println(area);              // ~78.539...
        System.out.println(MathUtils.callCount); // 1

        MathUtils mu = MathUtils.fromString("3.5");
        System.out.println(mu.doubled());      // 7.0
        System.out.println(MathUtils.callCount); // 2
    }
}

public class Config {
    // static final: class-level constant (UPPER_SNAKE_CASE by convention)
    static final int MAX_USERS = 100;
    static final String APP_NAME;
    static int loadOrder;

    // Static initialisation block: runs once when class is loaded
    static {
        APP_NAME  = "MyApp v1.0"; // can assign static final HERE
        loadOrder = 1;
        System.out.println("Class loaded: " + APP_NAME);
    }

    String username;

    public Config(String username) {
        this.username = username;
        System.out.println("Object created for: " + username);
    }

    public static void main(String[] args) {
        System.out.println("main() started");
        Config c1 = new Config("Alice");
        Config c2 = new Config("Bob");
        // Output:
        // Class loaded: MyApp v1.0   <- static block runs BEFORE main!
        // main() started
        // Object created for: Alice
        // Object created for: Bob
    }
}

public class Lamp {
    String color;
    int brightness;
    boolean isOn;

    public Lamp() {
        this("white", 50);
        System.out.println("Lamp() called");
    }

    public Lamp(String color, int brightness) {
        this(color, brightness, false);
        System.out.println("Lamp(color,brightness) called");
    }

    public Lamp(String color, int brightness, boolean isOn) {
        this.color      = color;
        this.brightness = brightness;
        this.isOn       = isOn;
        System.out.println("Lamp(color,brightness,isOn) called");
    }

    public static void main(String[] args) {
        Lamp a = new Lamp();
        System.out.println(a.color + " " + a.brightness + " " + a.isOn);
    }
}

public class Ticket {
    static int nextId = 1;
    int id;
    String event;

    public Ticket(String event) {
        this.id    = nextId;
        nextId++;
        this.event = event;
    }

    public static void main(String[] args) {
        Ticket t1 = new Ticket("Concert");
        Ticket t2 = new Ticket("Festival");
        System.out.println(t1.id + " " + t2.id);
        System.out.println(Ticket.nextId);

        Ticket t3 = new Ticket("Theatre");
        System.out.println(t3.id);
        System.out.println(t1.nextId); // same as Ticket.nextId

        t1 = new Ticket("Opera"); // t1 now references a NEW object
        System.out.println(t1.id);
    }
}

