public class Circle {
    double radius;
    static final double PI = 3.14159;

    public Circle(double radius) {
        this.radius = radius;
    }

    public double area() {
        return PI * radius * radius; // instance method: 'radius' is fine here
    }

    public static void main(String[] args) {
        Circle c = new Circle(5.0); // create an object first!
        System.out.println("Area: " + c.area()); // Area: 78.53975
    }
}

