// Design a Book class for a library system:
//   Static field: totalBooks (count of all Book objects created)
//   Instance fields: title (String), author (String), bookId (int)
//   Constructor: Book(String title, String author)
//     Automatically assigns bookId = totalBooks (after incrementing)
//   Static method: int getTotal() — returns totalBooks
//   Instance method: String toString() — returns "[id] title by author"
// In main: create 3 books and print them, then print the total count.

sections.solution:
public class Book {
    static int totalBooks = 0;

    int bookId;
    String title;
    String author;

    // Every time a Book is created, totalBooks increases
    public Book(String title, String author) {
        totalBooks++;         // increment shared counter first
        this.bookId = totalBooks; // assign this book's unique id
        this.title  = title;
        this.author = author;
    }

    public static int getTotal() {
        return totalBooks; // static method returns static field
    }

    public String toString() {
        return "[" + bookId + "] " + title + " by " + author;
    }

    public static void main(String[] args) {
        Book b1 = new Book("Clean Code",     "Robert Martin");
        Book b2 = new Book("Effective Java", "Joshua Bloch");
        Book b3 = new Book("The Pragmatic Programmer", "Hunt & Thomas");

        System.out.println(b1); // [1] Clean Code by Robert Martin
        System.out.println(b2); // [2] Effective Java by Joshua Bloch
        System.out.println(b3); // [3] The Pragmatic Programmer by Hunt & Thomas
        System.out.println("Total books: " + Book.getTotal()); // Total books: 3
    }
}
